// // This module takes a 4-bit input and outputs a 16-bit value where the highest 4 bits are the input, the next 4 bits are the input shifted right by 1, the following 4 bits are the input shifted right by 2, and the lowest 4 bits are the input shifted right by 3.
module top_module(
    input [3:0] in,
    output reg [15:0] out
);always @(*) begin
    out[15:12] = in;
    out[11:8] = in << 1;
    out[7:4] = in << 2;
    out[3:0] = in << 3;
end

endmodule
